/**
 * draggable 설정 함수
 * @private
 * @memberOf BxPaper
 */
function _initDrag(){

    let option = this[OPTS];
    let $paperWrap = this.$paperWrap;
    let onDrag = option.onDrag;

    let onDragStart = (e, $elem) =>{
        // dom Element 를 최하위로 옮겨 z-index 가 꼬이는 것을 방지한다.
        _moveContainerBottom.call(this);
        option.onDragStart.call(this, e, $elem);
    };

    let onDragStop = (e, $elem) =>{
        _setLastPosition.call(this);
        option.onDragStop.call(this, e, $elem);
    };

    let dragOption = {
        containment: "parent",
        snapMode: "inner",
        scroll: false,
        drag: onDrag,
        start: onDragStart,
        stop: onDragStop,
        handle: `.${uiConfig.className.structure.drag}`
        // cursor: 'crosshair',
        // cursorAt: { left: 5 }
    };

    $paperWrap.draggable(dragOption);
}

/**
 * 이벤트 설정 함수
 * @private
 * @memberOf BxPaper
 */
function _addEvent(){

    let $root = this.$root,
        $paperWrap = this.$paperWrap,
        $drag = $paperWrap.find(`.${uiConfig.className.structure.drag}`),
        closeBtnClass = `.${uiConfig.className.structure.btnWrap} .${uiConfig.className.structure.closeBtn}`,
        $focus = $paperWrap.find(`.${PAPER_STRUCTURE_CLASS_NAME.focus}`),
        focus = $focus.get(0);

    // 컨테이너 선택시, 가장 위에 오게 container 위치 조정 및 사용자 함수 call
    $drag.click((e) =>{

        if ($root.find(`.${this.containerClassName}`).length !== 1){
            _moveContainerBottom.call(this);
        }

        $focus.focus();
        this[OPTS].onActivate.call(this, e, $paperWrap);
    });

    $paperWrap.find(closeBtnClass).click(() =>{
        console.log('close btn click!!!');

        window.setTimeout(() =>{
            this.close();
        }, 0);
    });

    $paperWrap.on('focusin', function (e){

        window.setTimeout(()=>{
            UTIL.setPreFocusInstanceKey('hoverer');
        }, 0);
    });
}

/**
 * onRender 함수
 * @private
 * @memberOf BxPaper
 */
function _onRender(){

    this[OPTS].onRender.call(this);

    this.$paperWrap.find(`.${PAPER_STRUCTURE_CLASS_NAME.focus}`).focus();
}

